all_dfs = []

for freguesia, raw_str in raw_data.items():
    decoded = html.unescape(raw_str)
    data = json.loads(decoded)
    
    columns = data["data"]["columns"]
    datas = columns[0][1:]       
    valores = columns[1][1:]     
    
    df = pd.DataFrame({
        "Data": datas,
        freguesia: valores
    })
    all_dfs.append(df)

df_wide = all_dfs[0]
for df in all_dfs[1:]:
    df_wide = df_wide.merge(df, on="Data", how="outer")

meses = {
    "Jan": 1, "Fev": 2, "Mar": 3, "Abr": 4, "Mai": 5, "Jun": 6,
    "Jul": 7, "Ago": 8, "Set": 9, "Out": 10, "Nov": 11, "Dez": 12
}

def parse_mes_ano(mes_ano):
    try:
        mes_str, ano_str = mes_ano.split()
        mes_num = meses[mes_str[:3]]
        return pd.Timestamp(year=int(ano_str), month=mes_num, day=1)
    except:
        return pd.NaT

df_wide["Data"] = df_wide["Data"].apply(parse_mes_ano)

df_wide = df_wide.sort_values("Data").reset_index(drop=True)

df_wide = df_wide.loc[df_wide.drop(columns="Data").notna().any(axis=1)]

cols = ["Data"] + sorted([c for c in df_wide.columns if c != "Data"])
df_wide = df_wide[cols]

df_wide["Data"] = df_wide["Data"].dt.strftime('%b/%Y') 

path_wide = os.path.join(OUTPUT_DIR, "Lisboa_freguesias_preco_m2_wide.csv")
df_wide.to_csv(path_wide, index=False, encoding="utf-8-sig")

df_long = df_wide.melt(id_vars="Data", var_name="Freguesia", value_name="Preco_m2")

df_long = df_long.sort_values(["Data", "Freguesia"]).reset_index(drop=True)

path_long = os.path.join(OUTPUT_DIR, "Lisboa_freguesias_preco_m2_long.csv")
df_long.to_csv(path_long, index=False, encoding="utf-8-sig")